   107→func (rkv *retryKVClient) Range(ctx context.Context, in *pb.RangeRequest, opts ...grpc.CallOption) (resp *pb.RangeResponse, err error) {
   108→	return rkv.kc.Range(ctx, in, append(opts, withRepeatablePolicy())...)
   109→}
